const Badge = ({ children, color = "gold" }) => {
  const bg = color === "green" ? C.greenLight : color === "red" ? "rgba(192,57,43,0.1)" : color === "maroon" ? "rgba(140,26,17,0.08)" : C.goldMuted;
  const fg = color === "green" ? C.green : color === "red" ? C.red : color === "maroon" ? C.maroon : C.gold;
  return <span style={{ display: "inline-block", padding: "3px 11px", borderRadius: 0, fontSize: 11, fontWeight: 600, background: bg, color: fg, fontFamily: body }}>{children}</span>;
};
const Section = ({ children, bg = "transparent", style: s = {} }) => (
  <div style={{ padding: "72px 24px", background: bg, ...s }}><div style={{ maxWidth: 920, margin: "0 auto" }}>{children}</div></div>
);
const SectionTitle = ({ sub, children, light = false, center = false }) => (
  <div style={{ marginBottom: 40, textAlign: center ? "center" : "left" }}>
    {sub && <div style={{ fontSize: 11, fontWeight: 700, color: light ? C.goldBright : C.maroon, textTransform: "uppercase", letterSpacing: 3, marginBottom: 12, fontFamily: body }}>{sub}</div>}
    <h2 style={{ fontSize: 30, fontWeight: 700, color: light ? C.white : C.textDark, margin: 0, lineHeight: 1.2, fontFamily: display, letterSpacing: 1.5 }}>{children}</h2>
  </div>
);

